    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet]
    public async Task<IActionResult> GetProxy([FromUri] string url)
    {
        var client = _httpClientFactory.CreateClient();
        var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();
        return new OkObjectResult(await response.Content.ReadAsStringAsync());
    }

    [HttpPost]
    public async Task<IActionResult> PostProxy([FromBody] string url)
    {
        var client = _httpClientFactory.CreateClient();
        var response = await client.PostAsync(url, new StringContent(string.Empty, Encoding.UTF8, "text/plain"));
        response.EnsureSuccessStatusCode();
        return new OkObjectResult(await response.Content.ReadAsStringAsync());
    }
}
